            (f"{HOME}/.aws/credentials", "~/.aws"),
            (f"{HOME}/.aws/config", "~/.aws"),
            (f"{HOME}/.kube", "~/.kube"),
            (f"{HOME}/.kube/config", "~/.kube"),
