class TestExtractPathsBash:
    """Test path extraction from Bash commands."""

    def test_tilde_ssh(self) -> None:
        paths = block_paths.extract_paths_bash("cat ~/.ssh/id_rsa", "/tmp")
        resolved = [p for p in paths if ".ssh" in p]
        assert any(p == f"{HOME}/.ssh/id_rsa" for p in resolved)

    def test_dollar_home_ssh(self) -> None:
        paths = block_paths.extract_paths_bash("cat $HOME/.ssh/id_rsa", "/tmp")
        resolved = [p for p in paths if ".ssh" in p]
        assert any(p == f"{HOME}/.ssh/id_rsa" for p in resolved)

    def test_absolute_ssh(self) -> None:
        paths = block_paths.extract_paths_bash(f"cat {HOME}/.ssh/id_rsa", "/tmp")
        assert f"{HOME}/.ssh/id_rsa" in paths

    def test_relative_in_blocked_cwd(self) -> None:
        paths = block_paths.extract_paths_bash("cat id_rsa", f"{HOME}/.ssh")
        assert f"{HOME}/.ssh/id_rsa" in paths

    def test_mixed_command(self) -> None:
        cmd = "cp ~/.ssh/id_rsa /tmp/backup"
        paths = block_paths.extract_paths_bash(cmd, "/tmp")
        ssh_paths = [p for p in paths if ".ssh" in p]
        assert any(p == f"{HOME}/.ssh/id_rsa" for p in ssh_paths)

    def test_flags_skipped(self) -> None:
        paths = block_paths.extract_paths_bash("ls -la /tmp/safe", "/tmp")
        assert "/tmp/safe" in paths
        # -la should not appear as a resolved path containing .ssh etc.
        for p in paths:
            assert not p.endswith("-la")

    def test_safe_command_no_blocked(self) -> None:
        paths = block_paths.extract_paths_bash("ls /tmp/safe", "/tmp")
        for p in paths:
            assert block_paths.check_path(p) is None


