class TestCommandChaining:
    """Semicolon command chaining must be blocked in Bash commands."""

    @pytest.mark.parametrize(
        "command",
        [
            "FOO=ssh; ls ~/.${FOO}/",
            "ls /tmp; cat ~/.ssh/config",
            "echo hello; echo world",
            "cd /tmp; ls",
        ],
    )
    def test_semicolon_chaining_blocked(
        self, command: str, monkeypatch: pytest.MonkeyPatch
    ) -> None:
        data = {
            "tool_name": "Bash",
            "tool_input": {"command": command},
            "cwd": "/tmp",
        }
        monkeypatch.setattr(sys, "stdin", io.StringIO(json.dumps(data)))
        with pytest.raises(SystemExit) as exc_info:
            block_paths.main()
        assert exc_info.value.code == 2

    def test_semicolon_in_quotes_allowed(self, monkeypatch: pytest.MonkeyPatch) -> None:
        data = {
            "tool_name": "Bash",
            "tool_input": {"command": "grep 'foo;bar' /tmp/file.txt"},
            "cwd": "/tmp",
        }
        monkeypatch.setattr(sys, "stdin", io.StringIO(json.dumps(data)))
        block_paths.main()  # should not raise

    def test_semicolon_in_double_quotes_allowed(
        self, monkeypatch: pytest.MonkeyPatch
    ) -> None:
        data = {
            "tool_name": "Bash",
            "tool_input": {"command": 'grep "foo;bar" /tmp/file.txt'},
            "cwd": "/tmp",
        }
        monkeypatch.setattr(sys, "stdin", io.StringIO(json.dumps(data)))
        block_paths.main()  # should not raise

    def test_no_semicolon_allowed(self, monkeypatch: pytest.MonkeyPatch) -> None:
        data = {
            "tool_name": "Bash",
            "tool_input": {"command": "ls /tmp"},
            "cwd": "/tmp",
        }
        monkeypatch.setattr(sys, "stdin", io.StringIO(json.dumps(data)))
        block_paths.main()  # should not raise

    def test_chaining_message_on_stderr(
        self,
        monkeypatch: pytest.MonkeyPatch,
        capsys: pytest.CaptureFixture[str],
    ) -> None:
        data = {
            "tool_name": "Bash",
            "tool_input": {"command": "echo a; echo b"},
            "cwd": "/tmp",
        }
        monkeypatch.setattr(sys, "stdin", io.StringIO(json.dumps(data)))
        with pytest.raises(SystemExit):
            block_paths.main()
        captured = capsys.readouterr()
        assert "semicolon command chaining" in captured.err

    def test_chaining_only_applies_to_bash(
        self, monkeypatch: pytest.MonkeyPatch
    ) -> None:
        data = {
            "tool_name": "Read",
            "tool_input": {"file_path": "/tmp/file;name.txt"},
            "cwd": "/tmp",
        }
        monkeypatch.setattr(sys, "stdin", io.StringIO(json.dumps(data)))
        block_paths.main()  # should not raise


